// // This module designs a 4-bit binary down-counter that decrements its value on the falling edge of the clock signal (clk). When the reset signal is high, the counter resets to zero; otherwise, it continues counting downwards.
module top_module(clk, reset, count);input clk, reset;
   output reg [3:0] count;

   always @(posedge clk or negedge reset) begin
      if (reset == 0) begin
         count <= 0;
      end else begin
         count <= count + 1;
      end
   end

endmodule
